BEGIN; ALTER TABLE public.vehicles ADD COLUMN IF NOT EXISTS is_active boolean NOT NULL DEFAULT true; CREATE OR REPLACE FUNCTION public.vehicles_block_hard_delete() RETURNS trigger LANGUAGE plpgsql SET search_path = public AS $$ BEGIN RAISE EXCEPTION 'Bi chan de bao ve du lieu: khong duoc xoa cung xe. Hay ngung dung xe bang is_active=false.'; END; $$; DROP TRIGGER IF EXISTS trg_vehicles_block_delete ON public.vehicles; CREATE TRIGGER trg_vehicles_block_delete BEFORE DELETE ON public.vehicles FOR EACH ROW EXECUTE FUNCTION public.vehicles_block_hard_delete(); CREATE OR REPLACE FUNCTION public.deactivate_vehicle_v1(p_vehicle_id uuid) RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$ DECLARE v_user_id uuid := auth.uid(); v_vehicle public.vehicles%ROWTYPE; BEGIN IF v_user_id IS NULL OR NOT public.is_admin() THEN RAISE EXCEPTION 'Ban khong co quyen ngung dung xe.'; END IF; IF p_vehicle_id IS NULL THEN RAISE EXCEPTION 'Thieu xe can ngung dung.'; END IF; SELECT * INTO v_vehicle FROM public.vehicles WHERE id = p_vehicle_id FOR UPDATE; IF NOT FOUND THEN RAISE EXCEPTION 'Khong tim thay xe.'; END IF; UPDATE public.vehicles SET is_active = false WHERE id = p_vehicle_id; RETURN jsonb_build_object('id', p_vehicle_id, 'is_active', false); END; $$; GRANT EXECUTE ON FUNCTION public.deactivate_vehicle_v1(uuid) TO authenticated; NOTIFY pgrst, 'reload schema'; COMMIT;
